-    type MemBlockType    is array (integer range <>) of integer ;
-    type MemBlockPtrType is access MemBlockType ;
-    type MemArrayType    is array (integer range <>) of MemBlockPtrType ;
-    type MemArrayPtrType is access MemArrayType ; 
