-    ------------------------------------------------------------
-    begin
-      if IdOutOfRange(ID, "MemErase") then 
-        return ;
-      end if ; 
-
-      for BlockAddr in MemStructPtr(ID).MemArrayPtr'range loop 
-        if (MemStructPtr(ID).MemArrayPtr(BlockAddr) /= NULL) then 
-          deallocate (MemStructPtr(ID).MemArrayPtr(BlockAddr)) ; 
-        end if ; 
-      end loop ; 
-    end procedure ; 
