-  ------------------------------------------------------------
-  -- RequestTransaction - WaitForTransaction
-  --   RequestTransaction - Transaction initiation in transaction procedure
-  --   WaitForTransaction - Transaction execution control in VC
-  ------------------------------------------------------------
-  ------------------------------------------------------------
-  -- RequestTransaction - WaitForTransaction
-  --   std_logic
-  ------------------------------------------------------------
-  procedure RequestTransaction (
-    signal Rdy  : Out std_logic ;
-    signal Ack  : In  std_logic 
-  ) is
-  begin
-    -- Record contains new transaction
-    Rdy        <= '1' ;
-    -- Find Ack low = '0' 
-    wait until Ack = '0' ;
-    -- Prepare for Next Transaction
-    Rdy        <= '0' ;
-    -- Transaction Done
-    wait until Ack = '1' ;        
-  end procedure RequestTransaction ;
-  
-  procedure WaitForTransaction (
-    signal Clk  : In  std_logic ;
-    signal Rdy  : In  std_logic ;
-    signal Ack  : Out std_logic 
-  ) is
-    variable AckTime : time ; 
-  begin
-    -- End of Previous Cycle.  Signal Done
-    Ack        <= '1' ;               --  #6
-    AckTime    := NOW ; 
-    -- Find Start of Transaction
-    wait for 0 ns ; -- Allow Rdy from previous cycle to clear
-    if Rdy /= '1' then                --   #2
-      wait until Rdy = '1' ; 
-    end if ; 
-    -- align to clock if needed (not back-to-back transactions)
-    if NOW /= AckTime then 
-      wait until Clk = CLK_ACTIVE ;
-    end if ; 
-    -- Model active and owns the record
-    Ack        <= '0' ;               --  #3
-    wait for 0 ns ; -- Allow transactions without time passing
-  end procedure WaitForTransaction ;
-  
-  ------------------------------------------------------------
-  -- RequestTransaction - WaitForTransaction
-  --   bit
-  ------------------------------------------------------------
-  procedure RequestTransaction (
-    signal Rdy  : Out bit ;
-    signal Ack  : In  bit 
-  ) is
-  begin
-    -- Record contains new transaction
-    Rdy        <= '1' ;
-    -- Find Ack low = '0' 
-    wait until Ack = '0' ;
-    -- Prepare for Next Transaction
-    Rdy        <= '0' ;
-    -- Transaction Done
-    wait until Ack = '1' ;        
-  end procedure RequestTransaction ;
-  
-  procedure WaitForTransaction (
-    signal Clk  : In  std_logic ;
-    signal Rdy  : In  bit ;
-    signal Ack  : Out bit 
-  ) is
-    variable AckTime : time ; 
-  begin
-    -- End of Previous Cycle.  Signal Done
-    Ack        <= '1' ;               --  #6
-    AckTime    := NOW ; 
-    -- Find Start of Transaction
-    wait for 0 ns ; -- Allow Rdy from previous cycle to clear
-    if Rdy /= '1' then                --   #2
-      wait until Rdy = '1' ; 
-    else
-      wait for 0 ns ; -- allow Ack to update
-    end if ; 
-    -- align to clock if needed (not back-to-back transactions)
-    if NOW /= AckTime then 
-      wait until Clk = CLK_ACTIVE ;
-    end if ; 
-    -- Model active and owns the record
-    Ack        <= '0' ;               --  #3
-    wait for 0 ns ; -- Allow transactions without time passing
-  end procedure WaitForTransaction ;
-  
-  ------------------------------------------------------------
-  -- RequestTransaction - WaitForTransaction
-  --   integer
-  ------------------------------------------------------------
-  procedure RequestTransaction (
-    signal Rdy     : InOut RdyType ;
-    signal Ack     : In    AckType 
-  ) is
-  begin
-    -- Initiate Transaction Request
-    Rdy <= Increment(Rdy) ; 
-    wait for 0 ns ; 
-    
-    -- Wait for Transaction Completion
-    wait until Rdy = Ack ;     
-  end procedure RequestTransaction ;
-
-  procedure WaitForTransaction (
-    signal Clk      : In    std_logic ;
-    signal Rdy      : In    RdyType ;
-    signal Ack      : InOut AckType 
-  ) is
-    variable AckTime : time ; 
-  begin
-    -- End of Previous Cycle.  Signal Done
-    Ack <= Increment(Ack) ; 
-    AckTime    := NOW ; 
-    
-    -- Find Start of Transaction
-    wait until Ack /= Rdy ; 
-
-    -- Align to clock if needed (not back-to-back transactions)
-    if NOW /= AckTime then 
-      wait until Clk = CLK_ACTIVE ;
-    end if ; 
-  end procedure WaitForTransaction ;
-  
-  ------------------------------------------------------------
-  -- WaitForTransaction
-  --   Specializations for interrupt handling
-  --   Currently only std_logic based
-  ------------------------------------------------------------
-  procedure WaitForTransaction (
-    signal   Clk       : In  std_logic ;
-    signal   Rdy       : In  std_logic ;
-    signal   Ack       : Out std_logic ;
-    signal   TimeOut   : In  std_logic ;
-    constant Polarity  : In  std_logic := '1' 
-  ) is
-    variable AckTime : time ; 
-    variable FoundRdy : boolean ; 
-  begin
-    -- End of Previous Cycle.  Signal Done
-    Ack        <= '1' ;               --  #6
-    AckTime    := NOW ; 
-    -- Find Ready or Time out
-    wait for 0 ns ; -- Allow Rdy from previous cycle to clear
-    if (Rdy /= '1' and TimeOut /= Polarity) then 
-      wait until Rdy = '1' or TimeOut = Polarity ; 
-    end if ; 
-    FoundRdy := Rdy = '1' ; 
-    -- align to clock if Rdy or TimeOut does not happen within delta cycles from Ack
-    if NOW /= AckTime then 
-      wait until Clk = CLK_ACTIVE ;
-    end if ; 
-    if FoundRdy then 
-      -- Model active and owns the record
-      Ack        <= '0' ;             --  #3
-      wait for 0 ns ; -- Allow transactions without time passing
-    end if ;
-  end procedure WaitForTransaction ;
-  
-  -- Variation for model that stops waiting when IntReq is asserted
-  -- Intended for models that need to switch between instruction streams
-  -- such as a CPU when interrupt is pending
-  procedure WaitForTransactionOrIrq (
-    signal Clk     : In  std_logic ;
-    signal Rdy     : In  std_logic ;
-    signal IntReq  : In  std_logic 
-  ) is
-    variable AckTime : time ; 
-    constant POLARITY : std_logic := '1' ;
-  begin
-    AckTime    := NOW ; 
-    -- Find Ready or Time out
-    wait for 0 ns ; -- allow Rdy from previous cycle to clear
-    if (Rdy /= '1' and IntReq /= POLARITY) then 
-      wait until Rdy = '1' or IntReq = POLARITY ; 
-    else
-      wait for 0 ns ; -- allow Ack to update
-   end if ; 
-    -- align to clock if Rdy or IntReq does not happen within delta cycles from Ack
-    if NOW /= AckTime then 
-      wait until Clk = CLK_ACTIVE ;
-    end if ; 
-  end procedure ;
-  
-  -- Set Ack to Model starting value
-  -- Pairs with WaitForTransactionOrIrq above
-  procedure StartTransaction  ( signal Ack : Out std_logic ) is
-  begin
-    Ack        <= '0' ;
-    wait for 0 ns ; -- Allow transactions without time passing
-  end procedure StartTransaction ; 
-
-  -- Set Ack to Model finishing value
-  -- Pairs with WaitForTransactionOrIrq above
-  procedure FinishTransaction ( signal Ack : Out std_logic ) is
-  begin
-    -- End of Cycle
-    Ack        <= '1' ;
-    wait for 0 ns ; -- Allow Ack to update
-  end procedure FinishTransaction ; 
-
-  -- If a transaction is pending, return true
-  --   Used to detect presence of transaction stream, 
-  --   such as an interrupt handler
-  function TransactionPending (
-    signal Rdy     : In  std_logic 
-  ) return boolean is
-  begin
-    return Rdy = '1' ; 
-  end function TransactionPending ;
-
-  -- Variation for clockless models
-  procedure WaitForTransaction (
-    signal Rdy  : In  std_logic ;
-    signal Ack  : Out std_logic 
-  ) is
-    variable AckTime : time ; 
-  begin
-    -- End of Previous Cycle.  Signal Done
-    Ack        <= '1' ;               --  #6
-    -- Find Start of Transaction
-    wait for 0 ns ; -- Allow Rdy from previous cycle to clear
-    if Rdy /= '1' then                --   #2
-      wait until Rdy = '1' ; 
-    end if ; 
-    -- Model active and owns the record
-    Ack        <= '0' ;               --  #3
-    wait for 0 ns ; -- allow 0 time transactions
-  end procedure WaitForTransaction ;
