-  -- Integer type versions
-  procedure Increment (signal Sig : InOut integer ; constant RollOverValue : in integer := 0) is
-  begin
---!!    if Sig = integer'high then 
-    if Sig = 2**30-1 then -- for consistency with function increment
-      Sig <= RollOverValue ; 
-    else
-      Sig <= Sig + 1 ;
-    end if ; 
