+  ------------------------------------------------------------
+  -- RequestTransaction - WaitForTransaction
+  --   RequestTransaction - Transaction initiation in transaction procedure
+  --   WaitForTransaction - Transaction execution control in VC
+  ------------------------------------------------------------
+  ------------------------------------------------------------
+  -- RequestTransaction - WaitForTransaction
+  --   std_logic
+  ------------------------------------------------------------
+  procedure RequestTransaction (
+    signal Rdy  : Out std_logic ;
+    signal Ack  : In  std_logic
+  ) is
+  begin
+    -- Record contains new transaction
+    Rdy        <= '1' ;
+    -- Find Ack low = '0'
+    wait until Ack = '0' ;
+    -- Prepare for Next Transaction
+    Rdy        <= '0' ;
+    -- Transaction Done
+    wait until Ack = '1' ;
+  end procedure RequestTransaction ;
+
+  procedure WaitForTransaction (
+    signal Clk         : In  std_logic ;
+    signal Rdy         : In  std_logic ;
+    signal Ack         : Out std_logic ;
+    constant ClkActive : In std_logic := CLK_ACTIVE
+  ) is
+    variable AckTime : time ;
+  begin
+    -- End of Previous Cycle.  Signal Done
+    Ack        <= '1' ;               --  #6
+    AckTime    := NOW ;
+    -- Find Start of Transaction
+    wait for 0 ns ; -- Allow Rdy from previous cycle to clear
+    if Rdy /= '1' then                --   #2
+      wait until Rdy = '1' ;
+    else
+      wait for 0 ns ; -- allow Ack to update
+    end if ;
+    -- align to clock if needed (not back-to-back transactions)
+    if NOW /= AckTime then
+      wait until Clk = ClkActive ;
+    end if ;
+    -- Model active and owns the record
+    Ack        <= '0' ;               --  #3
+    wait for 0 ns ; -- Allow transactions without time passing
+  end procedure WaitForTransaction ;
+
+  -- Only for clockless models 
+  procedure WaitForTransaction (
+    signal Rdy  : In  std_logic ;
+    signal Ack  : Out std_logic
+  ) is
+  begin
+    -- End of Previous Cycle.  Signal Done
+    Ack        <= '1' ;               --  #6
+    -- Find Start of Transaction
+    wait for 0 ns ; -- Allow Rdy from previous cycle to clear
+    if Rdy /= '1' then                --   #2
+      wait until Rdy = '1' ;
+    end if ;
+    -- Model active and owns the record
+    Ack        <= '0' ;               --  #3
+    wait for 0 ns ; -- allow 0 time transactions
+  end procedure WaitForTransaction ;
+
+  ------------------------------------------------------------
+  -- RequestTransaction - WaitForTransaction
+  --   bit
+  ------------------------------------------------------------
+  procedure RequestTransaction (
+    signal Rdy  : Out bit ;
+    signal Ack  : In  bit
+  ) is
+  begin
+    -- Record contains new transaction
+    Rdy        <= '1' ;
+    -- Find Ack low = '0'
+    wait until Ack = '0' ;
+    -- Prepare for Next Transaction
+    Rdy        <= '0' ;
+    -- Transaction Done
+    wait until Ack = '1' ;
+  end procedure RequestTransaction ;
+
+  procedure WaitForTransaction (
+    signal Clk         : In  std_logic ;
+    signal Rdy         : In  bit ;
+    signal Ack         : Out bit ;
+    constant ClkActive : In std_logic := CLK_ACTIVE
+  ) is
+    variable AckTime : time ;
+  begin
+    -- End of Previous Cycle.  Signal Done
+    Ack        <= '1' ;               --  #6
+    AckTime    := NOW ;
+    -- Find Start of Transaction
+    wait for 0 ns ; -- Allow Rdy from previous cycle to clear
+    if Rdy /= '1' then                --   #2
+      wait until Rdy = '1' ;
+    else
+      wait for 0 ns ; -- allow Ack to update
+    end if ;
+    -- align to clock if needed (not back-to-back transactions)
+    if NOW /= AckTime then
+      wait until Clk = ClkActive ;
+    end if ;
+    -- Model active and owns the record
+    Ack        <= '0' ;               --  #3
+    wait for 0 ns ; -- Allow transactions without time passing
+  end procedure WaitForTransaction ;
+
+  -- Only for clockless models 
+  procedure WaitForTransaction (
+    signal Rdy  : in  bit ;
+    signal Ack  : out bit
+  ) is
+  begin
+    -- End of Previous Cycle.  Signal Done
+    Ack        <= '1' ;               --  #6
+    -- Find Start of Transaction
+    wait for 0 ns ; -- Allow Rdy from previous cycle to clear
+    if Rdy /= '1' then                --   #2
+      wait until Rdy = '1' ;
+    end if ;
+    -- Model active and owns the record
+    Ack        <= '0' ;               --  #3
+    wait for 0 ns ; -- allow 0 time transactions
+  end procedure WaitForTransaction ;
