+        when X"1"   => result(i) := '1';
+        when X"2"   => result(i) := '2';
+        when X"3"   => result(i) := '3';
+        when X"4"   => result(i) := '4';
+        when X"5"   => result(i) := '5';
+        when X"6"   => result(i) := '6';
+        when X"7"   => result(i) := '7';
+        when X"8"   => result(i) := '8';
+        when X"9"   => result(i) := '9';
